-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH base_equipment AS (
    SELECT * FROM {{ ref('stg_eqpmnt_aar_base') }}
),

non_registered AS (
    SELECT * FROM {{ ref('stg_eqpmnt_non_rgstrd') }}
),

-- CPR Equipment Pool Lookup
lkp_cpr_pool AS (
    SELECT
        eab.MARK_CD,
        eab.EQPUN_NBR,
        ep.CPR_EQPMNT_POOL_ID
    FROM {{ source('mock_sources', 'EQPMNT_AAR_BASE') }} eab
    JOIN {{ source('mock_sources', 'EQPMNT_POOL_ASGNMN') }} epa
        ON eab.EQPMNT_ID = epa.EQPMNT_ID
    JOIN {{ source('mock_sources', 'EQPMNT_POOL') }} ep
        ON epa.EQPMNT_POOL_ID = ep.EQPMNT_POOL_ID
    QUALIFY ROW_NUMBER() OVER (PARTITION BY eab.MARK_CD, eab.EQPUN_NBR ORDER BY epa.EQPMNT_POOL_ASGNMN_ID DESC) = 1
),

-- Equipment Mark Owner Class Lookup
lkp_mark_owner AS (
    SELECT
        STNCL_MARK_OWNER_CLASS_CD AS MARK_OWNER_CLASS_CD,
        MARK_OWNER_CTGRY_CD
    FROM {{ source('mock_sources', 'EQPMNT_MARK_OWNER_CLASS_CD') }}
),

-- Equipment Party Lookup (Lessee)
lkp_party AS (
    SELECT
        TRY_TO_NUMBER(EQPMNT_ID) AS EQPMNT_ID,
        MARK_CD AS LESSEE_MARK_CD
    FROM (
        SELECT
            ep.EQPMNT_ID,
            ep.MARK_CD,
            ep.ENTITY_IDNTFR_CD,
            ROW_NUMBER() OVER (PARTITION BY EQPMNT_ID ORDER BY RECORD_UPDATE_TMS DESC) AS RNK
        FROM {{ source('mock_sources', 'EQPMNT_PARTY') }} ep
    ) x
    WHERE RNK = 1 AND ENTITY_IDNTFR_CD = 'LS'
),

-- Existing DIM Equipment Lookup
lkp_existing_dim AS (
    SELECT
        TRY_TO_NUMBER(DIM_EQUIPMENT_ID) AS DIM_EQUIPMENT_ID,
        TRIM(EQPUN_NBR) AS EQPUN_NBR,
        TRIM(MARK_CD) AS MARK_CD
    FROM {{ source('mock_sources', 'DIM_EQUIPMENT') }}
    WHERE EDW_CURRENT_FLG = 'N' AND EDW_END_EFCTV_DT IS NULL
),

-- Max DIM Equipment ID Lookup
lkp_max_id AS (
    SELECT
        MAX(TRY_TO_NUMBER(DIM_EQUIPMENT_ID)) AS MAX_DIM_EQUIPMENT_ID
    FROM {{ source('mock_sources', 'DIM_EQUIPMENT') }}
    WHERE EDW_CURRENT_FLG = 'Y'
),

-- Customer Registered Mark Lookup
lkp_customer_mark AS (
    SELECT MARK_CD
    FROM {{ source('mock_sources', 'CSTMR_RGSTRD_MARK_JN_GRP') }}
),

-- AAR Equipment Pool Lookup
lkp_aar_pool AS (
    SELECT
        TRY_TO_NUMBER(EQPMNT_POOL_ID) AS EQPMNT_POOL_ID,
        AAR_EQPMNT_POOL_ID
    FROM {{ source('mock_sources', 'EQPMNT_POOL') }}
),

-- Car Kind Translation Lookup
lkp_car_kind AS (
    SELECT
        CAR_KIND_CD,
        START_AAR_CAR_CD,
        END_AAR_CAR_CD
    FROM {{ source('mock_sources', 'EME_CAR_KIND_TRNSLT_PRCS') }}
),

-- Locomotive HP Lookup
lkp_loco_hp AS (
    SELECT
        MARK_CD,
        EQPUN_NBR,
        HRSPWR_QTY
    FROM {{ source('mock_sources', 'DIM_LOCOMOTIVE') }}
)

SELECT
    be.*,
    cpr.CPR_EQPMNT_POOL_ID,
    mo.MARK_OWNER_CTGRY_CD,
    p.LESSEE_MARK_CD,
    ed.DIM_EQUIPMENT_ID AS EXISTING_DIM_EQUIPMENT_ID,
    mi.MAX_DIM_EQUIPMENT_ID,
    CASE WHEN cm.MARK_CD IS NOT NULL THEN 'Y' ELSE 'N' END AS REGISTERED_IND,
    ap.AAR_EQPMNT_POOL_ID,
    ck.CAR_KIND_CD,
    lh.HRSPWR_QTY
FROM base_equipment be
LEFT JOIN lkp_cpr_pool cpr
    ON be.MARK_CD = cpr.MARK_CD AND be.EQPUN_NBR = cpr.EQPUN_NBR
LEFT JOIN lkp_mark_owner mo
    ON be.STNCL_MARK_OWNER_CLASS_CD = mo.MARK_OWNER_CLASS_CD
LEFT JOIN lkp_party p
    ON be.EQPMNT_ID = p.EQPMNT_ID
LEFT JOIN lkp_existing_dim ed
    ON TRIM(be.MARK_CD) = ed.MARK_CD AND TRIM(be.EQPUN_NBR) = ed.EQPUN_NBR
CROSS JOIN lkp_max_id mi
LEFT JOIN lkp_customer_mark cm
    ON be.MARK_CD = cm.MARK_CD
LEFT JOIN lkp_aar_pool ap
    ON be.EQPMNT_POOL_ID = ap.EQPMNT_POOL_ID
LEFT JOIN lkp_car_kind ck
    ON be.AAR_CAR_CD >= ck.START_AAR_CAR_CD AND be.AAR_CAR_CD <= ck.END_AAR_CAR_CD
LEFT JOIN lkp_loco_hp lh
    ON be.MARK_CD = lh.MARK_CD AND be.EQPUN_NBR = lh.EQPUN_NBR
